		CREATE TABLE IF NOT EXISTS clicks (
			id TEXT NOT NULL,
			timestamp TEXT
		);
	`)
	if err != nil {
		fmt.Println(err)
		return
	}

	app.Post("/click", registerClick)
	app.Get("/clicks", getClicks)

	port := os.Getenv("PORT")
	if port == "" {
		port = "5000"
	}

	err = app.Listen(":5000")
	if err != nil {
		fmt.Println(err)
		return
	}
