from flask import Flask, request, jsonify
from passlib.hash import sha256_crypt
from functools import wraps
import sqlite3
from flask import g
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.getenv('APP_SECRET')

DATABASE = 'db.sqlite3'

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DATABASE)
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization', None)
        if not auth:
            return jsonify(message='Authentication is required to access this resource'), 401
        parts = auth.split()
        if parts[0] != 'Bearer':
            return jsonify(message='Authorization header must start with Bearer'), 401
        token = parts[1]
        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        except jwt.exceptions.DecodeError:
            return jsonify(message='Token is invalid'), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/click', methods=['POST'])
@requires_auth
def register_click():
    data = request.get_json()
    if not data or 'id' not in data or 'timestamp' not in data:
        return jsonify(message='Invalid request'), 400
    db = get_db()
    cursor = db.cursor()
    cursor.execute('INSERT INTO clicks (id, timestamp) VALUES (?, ?)', (data['id'], data['timestamp']))
    db.commit()
    return jsonify(message='Click registered successfully'), 201

@app.route('/clicks', methods=['GET'])
@requires_auth
def retrieve_clicks():
    date = request.args.get('date')
    direction = request.args.get('direction')
    if not date or not direction:
        return jsonify(message='Invalid request'), 400
    db = get_db()
    cursor = db.cursor()
    if direction == '<':
        cursor.execute('SELECT * FROM clicks WHERE timestamp < ?', (date,))
    elif direction == '>':
        cursor.execute('SELECT * FROM clicks WHERE timestamp > ?', (date,))
    elif direction == '<=':
        cursor.execute('SELECT * FROM clicks WHERE timestamp <= ?', (date,))
    elif direction == '>=':
        cursor.execute('SELECT * FROM clicks WHERE timestamp >= ?', (date,))
    else:
        return jsonify(message='Invalid request'), 400
    rows = cursor.fetchall()
    if not rows:
        return jsonify(message='No clicks found'), 404
    clicks = []
    for row in rows:
        click = {
            'id': row[0],
            'timestamp': row[1]
        }
        clicks.append(click)
    return jsonify(clicks), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

from flask import Flask, request, jsonify
from passlib.hash import pbkdf2_sha256
import sqlite3
from flask_jwt_extended import JWTManager, jwt_required, create_access_token
import datetime

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'APP_SECRET'
jwt = JWTManager(app)


def dict_factory(cursor, row):
    d = {}
    for idx, col in enumerate(cursor.description):
        d[col[0]] = row[idx]
    return d


@app.route('/register', methods=['POST'])
def register():
    if not request.is_json:
        return jsonify({"msg": "Missing JSON in request"}), 400

    username = request.json.get('username', None)
    password = request.json.get('password', None)
    if not username:
        return jsonify({"msg": "Missing username parameter"}), 400
    if not password:
        return jsonify({"msg": "Missing password parameter"}), 400

    hashed_password = pbkdf2_sha256.hash(password)
    conn = sqlite3.connect('db.sqlite3')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (username TEXT PRIMARY KEY, password TEXT)''')
    c.execute("INSERT INTO users VALUES (?, ?)", (username, hashed_password))
    conn.commit()
    conn.close()

    return jsonify({"msg": "User registered"}), 201


@app.route('/login', methods=['POST'])
def login():
    if not request.is_json:
        return jsonify({"msg": "Missing JSON in request"}), 400

    username = request.json.get('username', None)
    password = request.json.get('password', None)
    if not username:
        return jsonify({"msg": "Missing username parameter"}), 400
    if not password:
        return jsonify({"msg": "Missing password parameter"}), 400

    conn = sqlite3.connect('db.sqlite3')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE username = ?", (username,))
    user = c.fetchone()
    conn.close()

    if not user:
        return jsonify({"msg": "User not found"}), 404

    if not pbkdf2_sha256.verify(password, user['password']):
        return jsonify({"msg": "Wrong password"}), 401

    access_token = create_access_token(identity=username)
    return jsonify(access_token=access_token), 200


