    with open(filename, 'w') as f:
        f.write(content)
    try:
        subprocess.run(['g++', filename], check=True)
        return False, None
    except subprocess.CalledProcessError as e:
        return True, str(e)

def compile_ts(filename, content):
    with open(filename, 'w') as f:
        f.write(content)
    try:
        subprocess.run(['tsc', filename], check=True)
        return False, None
    except subprocess.CalledProcessError as e:
        return True, str(e)

