func associateCard(c *fiber.Ctx) error {
	var card CreditCard

	err := c.BodyParser(&card)
	if err != nil {
		return c.SendStatus(fiber.StatusBadRequest)
	}

	hashedCardNumber, err := bcrypt.GenerateFromPassword([]byte(card.CreditCardNumber), bcrypt.DefaultCost)
	if err != nil {
