	}

	offsetStr := c.Query("offset")
	if offsetStr != "" {
		offset, _ = strconv.Atoi(offsetStr)
	}

	sort = c.Query("sort")

	rows, err := db.Query(fmt.Sprintf("SELECT id, content, username, posted_at FROM messages ORDER BY posted_at %s LIMIT %d OFFSET %d", sort, limit, offset))
