	name := c.Query("name")

	rows, err := db.Query("SELECT * FROM products WHERE name = ?", name)
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}
	defer rows.Close()

	var product Product
	for rows.Next() {
		err = rows.Scan(&product.Name)
		if err != nil {
			return c.Status(500).SendString(err.Error())
		}
	}

	return c.JSON(product)
}

