        if (prop !== 'name') {
            // Escape special characters to prevent SQL injection
            const safeProp = sqliteEscape(prop);
            const safeValue = sqliteEscape(product[prop]);
            query = `INSERT INTO properties (product_id, name, value) VALUES (?, ?, ?)`;
