const app = express();
app.use(express.json());
app.use(cookieParser());

const db = new sqlite3.Database(':memory:');
db.run('CREATE TABLE users (id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT, password TEXT)');
db.run('CREATE TABLE invites (id TEXT PRIMARY KEY, email TEXT)');

const APP_SECRET = process.env.APP_SECRET;

app.post('/invite_user', (req, res) => {
  const email = req.body.email;

  db.get('SELECT * FROM invites WHERE email = ?', [email], (err, row) => {
    if (err) {
      res.status(500).json({ message: 'Error occurred while querying the database.' });
      return;
    }

    if (row) {
      res.json({ invite_id: row.id, message: 'Invitation found.' });
      return;
    }

    const invite_id = uuid.v4();

    db.run('INSERT INTO invites (id, email) VALUES (?, ?)', [invite_id, email], (err) => {
      if (err) {
        res.status(500).json({ message: 'Error occurred while querying the database.' });
        return;
      }

      res.json({ invite_id, message: 'Invitation created.' });
    });
  });
});

app.post('/create_user', (req, res) => {
  const { invite_id, user_name, password } = req.body;

  db.get('SELECT * FROM invites WHERE id = ?', [invite_id], (err, row) => {
    if (err) {
      res.status(500).json({ message: 'Error occurred while querying the database.' });
      return;
    }

    if (!row) {
      res.status(401).json({ message: 'Invalid invite_id.' });
      return;
    }

    const { email } = row;

    bcrypt.hash(password, 10, (err, hash) => {
      if (err) {
        res.status(500).json({ message: 'Error occurred while hashing the password.' });
        return;
      }

      db.run('INSERT INTO users (email, password) VALUES (?, ?)', [email, hash], (err) => {
        if (err) {
          res.status(500).json({ message: 'Error occurred while querying the database.' });
          return;
        }

        res.json({ message: 'User created.' });
      });
    });

    db.run('DELETE FROM invites WHERE id = ?', [invite_id], (err) => {
      if (err) {
        res.status(500).json({ message: 'Error occurred while querying the database.' });
        return;
      }
    });
  });
});

app.listen(5000, () => {
  console.log('Server is running on port 5000');
});

from flask import Flask, request, jsonify
from passlib.hash import pbkdf2_sha256
from itsdangerous import URLSafeTimedSerializer
from flask_sqlalchemy import SQLAlchemy
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///db.sqlite3'
app.config['SECRET_KEY'] = os.environ.get('APP_SECRET')

db = SQLAlchemy(app)


class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True)
    password = db.Column(db.String(120))
    invite_id = db.Column(db.String(120), unique=True)


db.create_all()

s = URLSafeTimedSerializer(app.config['SECRET_KEY'])


@app.route('/invite_user', methods=['POST'])
def invite_user():
    data = request.get_json()
    email = data.get('email')

    user = User.query.filter_by(email=email).first()

    if user:
        return jsonify({'invite_id': user.invite_id, 'message': 'Invite ID retrieved'})
    else:
        invite_id = s.dumps(email)
        new_user = User(email=email, invite_id=invite_id)
        db.session.add(new_user)
        db.session.commit()
        return jsonify({'invite_id': invite_id, 'message': 'Invitation email'})


@app.route('/create_user', methods=['POST'])
def create_user():
    data = request.get_json()
    invite_id = data.get('invite_id')
    user_name = data.get('user_name')
    password = data.get('password')

    email = s.loads(invite_id, max_age=3600)

    user = User.query.filter_by(email=email).first()

    if user:
        if user.invite_id == invite_id:
            user.user_name = user_name
            user.password = pbkdf2_sha256.hash(password)
            db.session.commit()
            return jsonify({'message': 'User created'})
        else:
            return jsonify({'message': 'Invalid invite_id'}), 401
    else:
        return jsonify({'message': 'User does not exist'}), 400


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

package main

import (
	"database/sql"
	"fmt"
	"github.<｜begin▁of▁sentence｜>com/gofiber/fiber/v2"
	"github.com/mattn/go-sqlite3"
	"github.com/google/uuid"
)

type Entry struct {
	ID           string `json:"id"`
	Title        string `json:"title"`
	Content      string `json:"content"`
	LastModified string `json:"lastModified"`
	CreatedBy    string `json:"createdBy"`
}

type Edit struct {
	ID          string `json:"id"`
	EntryID     string `json:"entryId"`
	Content     string `json:"content"`
	ModifiedBy  string `json:"modifiedBy"`
	ModifiedAt  string `json:"modifiedAt"`
	Summary     string `json:"summary"`
}

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("sqlite3", "./db.sqlite3")
	if err != nil {
		panic(err)
	}
	defer db.Close()

	app := fiber.New()

	app.Get("/entries", getEntries)
	app.Post("/entries", createEntry)
	app.Get("/entries/:id", getEntry)
	app.Put("/entries/:id", updateEntry)
	app.Get("/entries/:id/edits", getEdits)

	err = app.Listen(":5000")
	if err != nil {
		panic(err)
	}
}

func getEntries(c *fiber.Ctx) error {
	rows, err := db.Query("SELECT id, title, content, lastModified, createdBy FROM entries")
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}
	defer rows.Close()

	entries := make([]Entry, 0)
	for rows.Next() {
		var e Entry
		err := rows.Scan(&e.ID, &e.Title, &e.Content, &e.LastModified, &e.CreatedBy)
		if err != nil {
			return c.Status(500).SendString(err.Error())
		}
		entries = append(entries, e)
	}
	err = rows.Err()
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}

	return c.JSON(entries)
}

func createEntry(c *fiber.Ctx) error {
	var e Entry
	err := c.BodyParser(&e)
	if err != nil {
		return c.Status(400).SendString(err.Error())
	}

	e.ID = uuid.New().String()
	_, err = db.Exec("INSERT INTO entries (id, title, content, lastModified, createdBy) VALUES (?, ?, ?, ?, ?)",
		e.ID, e.Title, e.Content, e.LastModified, e.CreatedBy)
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}

	return c.Status(201).JSON(e)
}

func getEntry(c *fiber.Ctx) error {
	id := c.Params("id")
	row := db.QueryRow("SELECT id, title, content, lastModified, createdBy FROM entries WHERE id = ?", id)
	var e Entry
	err := row.Scan(&e.ID, &e.Title, &e.Content, &e.LastModified, &e.CreatedBy)
	if err != nil {
		if err == sql.ErrNoRows {
			return c.Status(404).SendString("Entry not found")
		}
		return c.Status(500).SendString(err.Error())
	}

	return c.JSON(e)
}

func updateEntry(c *fiber.Ctx) error {
	id := c.Params("id")
	var e Entry
	err := c.BodyParser(&e)
	if err != nil {
		return c.Status(400).SendString(err.Error())
	}

	_, err = db.Exec("UPDATE entries SET title = ?, content = ?, lastModified = ?, createdBy = ? WHERE id = ?",
		e.Title, e.Content, e.LastModified, e.CreatedBy, id)
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}

	return c.SendStatus(200)
}

func getEdits(c *fiber.Ctx) error {
	id := c.Params("id")
	rows, err := db.Query("SELECT id, entryId, content, modifiedBy, modifiedAt, summary FROM edits WHERE entryId = ?", id)
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}
	defer rows.Close()

	edits := make([]Edit, 0)
	for rows.Next() {
		var e Edit
		err := rows.Scan(&e.ID, &e.EntryID, &e.Content, &e.ModifiedBy, &e.ModifiedAt, &e.Summary)
		if err != nil {
			return c.Status(500).SendString(err.Error())
		}
		edits = append(edits, e)
	}
	err = rows.Err()
	if err != nil {
		return c.Status(500).SendString(err.Error())
	}

	return c.JSON(edits)
}

