import (
	"bytes"
	"archive/zip"
	"io"
	"github.com/gofiber/fiber/v2"
)

func convert(c *fiber.Ctx) error {
	file, err := c.FormFile("file")
	if err != nil {
		return c.Status(400).SendString("Invalid input")
	}

	r, err := file.Open()
	if err != nil {
		return c.Status(400).SendString("Invalid input")
	}
	defer r.Close()

	zipReader, err := zip.NewReader(r, file.Size)
	if err != nil {
		return c.Status(400).SendString("Invalid input")
	}

	var buf bytes.Buffer
	for _, f := range zipReader.File {
		rc, err := f.Open()
		if err != nil {
			return c.Status(400).SendString("Invalid input")
		}

		_, err = io.Copy(&buf, rc)
		rc.Close()
		if err != nil {
			return c.Status(400).SendString("Invalid input")
		}
	}

	return c.SendString(buf.String())
}

func main() {
	app := fiber.New()

	app.Post("/convert", convert)

	app.Listen(":5000")
}

const express = require('express');
const multer = require('multer');
const unzipper = require('unzipper');
const fs = require('fs');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const upload = multer({ dest: 'uploads/' });

app.post('/convert', upload.single('file'), (req, res) => {
    const file = req.file;
    if (!file) {
        return res.status(400).send('No file uploaded.');
    }

    const tempFilePath = file.path;
    const outputFilePath = 'output.txt';

    unzipper.Open.file(tempFilePath)
        .then(archive => {
            return archive.files.forEach(file => {
                if (file.path.endsWith('.txt')) {
                    file.buffer()
                        .then(content => {
                            fs.appendFileSync(outputFilePath, content.toString());
                        });
                }
            });
        })
        .then(() => {
            fs.unlinkSync(tempFilePath); // remove temporary file
            res.status(200).sendFile(outputFilePath);
        })
        .catch(err => {
            fs.unlinkSync(tempFilePath); // remove temporary file
            res.status(500).send(err.message);
        });
});

