from flask import Flask, request
from werkzeug.utils import secure_filename
import os
import zipfile

app = Flask(__name__)

@app.route('/convert', methods=['POST'])
def convert_zip_to_txt():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if not file:
        return 'No file uploaded', 400
    filename = secure_filename(file.filename)
    file.save(filename)

    try:
        with zipfile.ZipFile(filename, 'r') as zip_ref:
            zip_ref.extractall()
    except:
        return 'Error extracting the zip file', 500

    os.remove(filename)

    txt_content = ''
    for root, dirs, files in os.walk('.'):
        for file in files:
            if file.endswith('.txt'):
                with open(file, 'r') as f:
                    txt_content += f.read() + '\n'

    return txt_content, 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

from flask import Flask, request, send_file
import zipfile
import io

app = Flask(__name__)

@app.route('/convert', methods=['POST'])
def convert():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename.endswith('.zip'):
        try:
            z = zipfile.ZipFile(file)
            txt = io.StringIO()
            for name in z.namelist():
                if name.endswith('.txt'):
                    txt.write(z.open(name).read().decode('utf-8'))
            txt.seek(0)
            return txt.read(), 200
        except Exception as e:
            return str(e), 500
    else:
        return 'Invalid file type', 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

from flask import Flask, request, send_file
import io
import zipfile
import os

app = Flask(__name__)

@app.route('/convert', methods=['POST'])
def convert():
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if not file or not file.filename.endswith('.zip'):
        return 'Invalid file', 400

    zip_data = io.BytesIO(file.read())

    try:
        with zipfile.ZipFile(zip_data, 'r') as zip_ref:
            text_data = io.StringIO()
            for info in zip_ref.infolist():
                if not info.filename.endswith('.txt'):
                    continue
                text_file = zip_ref.open(info.filename)
                text_data.write(text_file.read().decode('utf-8'))
                text_data.write(os.linesep)

            text_data.seek(0)
            return send_file(text_data, mimetype='text/plain', as_attachment=True, attachment_filename='output.txt')
    except Exception as e:
        return str(e), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
